import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  AMINO_ACID = 'Amino Acid',
  MONOAMINE = 'Monoamine',
  NEUROPEPTIDE = 'Neuropeptide',
  PURINE = 'Purine',
  ENDOCANNABINOID = 'Endocannabinoid',
  GASOTRANSMITTER = 'Gasotransmitter'
}

export enum ActionType {
  EXCITATORY = 'Excitatory',
  INHIBITORY = 'Inhibitory',
  MODULATORY = 'Modulatory'
}

export enum EduMode {
  BEGINNER = 'Beginner',
  CLINICAL = 'Clinical',
  RESEARCH = 'Research'
}

export interface Receptor {
  name: string;
  type: 'Ionotropic' | 'Metabotropic';
  subtypes: string[];
}

export interface DisorderImpact {
  condition: string;
  lowLevelEffect: string;
  highLevelEffect: string;
}

export interface Neurotransmitter {
  id: string;
  name: string;
  symbol?: string;
  category: Category;
  action: ActionType;
  chemicalFormula: string;
  chemicalStructureDescription: string;
  precursors: string[];
  primaryReceptors: Receptor[];
  brainRegions: string[];
  functions: string[];
  disorders: DisorderImpact[];
  naturalModulators: {
    foods: string[];
    activities: string[];
    lifestyle: string[];
  };
  pharmaceuticals: {
    agonists: string[];
    antagonists: string[];
    reuptakeInhibitors: string[];
  };
  relatedNeurotransmitters: string[];
  clinicalNotes: string;
  researchNotes: string;
  image: string;
}

