import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const API_KEY = process.env.API_KEY;

export const getAIInsights = async (
  neuroA: string, 
  neuroB: string, 
  mode: string
): Promise<string> => {
  if (!API_KEY) return "AI Insights unavailable (API Key missing).";

  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Act as a clinical neuroscientist. 
  Provide a professional analysis comparing ${neuroA} and ${neuroB}. 
  Tailor your explanation for a ${mode} audience.
  Focus on:
  1. Synergistic or antagonistic relationship.
  2. Common clinical disorders where both are involved.
  3. Key differences in their mechanisms.
  Keep it structured with bullet points.`;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error generating insights. Please check your connection.";
  }
};

export const getSingleInsights = async (
  name: string,
  mode: string
): Promise<string> => {
  if (!API_KEY) return "AI Insights unavailable.";

  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Act as a senior neurologist. Provide a deep-dive summary for ${name}.
  The audience is ${mode}. 
  Structure the response with 'Did you know?' facts and a 'Clinical Pearl'.`;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error generating insights.";
  }
}

import React, { useState } from 'react';

interface AccordionProps {
  title: string;
  children: React.ReactNode;
  defaultOpen?: boolean;
}

const Accordion: React.FC<AccordionProps> = ({ title, children, defaultOpen = false }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="border-b border-slate-200">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between py-4 px-2 text-left transition-all hover:bg-slate-50"
      >
        <span className="text-lg font-semibold text-slate-800">{title}</span>
        <svg
          className={`w-6 h-6 transform transition-transform ${isOpen ? 'rotate-180' : ''}`}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>
      <div
        className={`overflow-hidden transition-all duration-300 ${
          isOpen ? 'max-h-[2000px] pb-6 px-4' : 'max-h-0'
        }`}
      >
        <div className="text-slate-600 leading-relaxed">
          {children}
        </div>
      </div>
    </div>
  );
};

export default Accordion;

