            onClick={handleRunAnalysis}
            disabled={loading}
            className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-full font-bold transition-all shadow-md shadow-indigo-100 flex items-center gap-2"
