      <div className="h-20"></div>
    </div>
  );
};

export default CompareView;

import React, { useState, useMemo } from 'react';
import { neurotransmitters } from './data/neurotransmitters';
import { Category, ActionType, EduMode, Neurotransmitter } from './types';
import Layout from './components/Layout';
import NeuroDetail from './components/NeuroDetail';
import CompareView from './components/CompareView';

type ViewState = 'list' | 'detail' | 'compare';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('list');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'All'>('All');
  const [eduMode, setEduMode] = useState<EduMode>(EduMode.BEGINNER);
  const [isMobileView, setIsMobileView] = useState(false);

  const filteredItems = useMemo(() => {
    return neurotransmitters.filter(item => {
      const matchesSearch = 
        item.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.chemicalFormula.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.disorders.some(d => d.condition.toLowerCase().includes(searchQuery.toLowerCase()));
      const matchesCategory = filterCategory === 'All' || item.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, filterCategory]);

  const currentNeuro = neurotransmitters.find(n => n.id === selectedId);

  const handleNavigate = (id: string) => {
    setSelectedId(id);
    setView('detail');
  };

  const renderContent = () => {
    if (view === 'compare') {
      return <CompareView data={neurotransmitters} mode={eduMode} />;
    }

    if (view === 'detail' && currentNeuro) {
      return <NeuroDetail item={currentNeuro} mode={eduMode} onNavigate={handleNavigate} />;
    }

    return (
      <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8 animate-fadeIn">
        {/* Dashboard Header */}
        <section className="bg-indigo-600 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
          <div className="relative z-10 max-w-2xl">
            <h2 className="text-3xl font-extrabold mb-2">Neuro-Explorer Hub</h2>
            <p className="text-indigo-100 mb-6">Explore the complex chemical landscape of the human brain with structured data and AI clinical insights.</p>
            <div className="flex items-center space-x-2">
              <div className="bg-indigo-500/50 rounded-lg p-1 flex">
                {(Object.values(EduMode)).map(mode => (
                  <button
                    key={mode}
                    onClick={() => setEduMode(mode)}
                    className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${eduMode === mode ? 'bg-white text-indigo-600 shadow-sm' : 'text-white hover:bg-white/10'}`}
                  >
                    {mode}
                  </button>
                ))}
              </div>
